code = """import json
import pandas as pd
import numpy as np
import re

# Load data
clinical_data_path = locals()['var_function-call-10669084474385643159']
molecular_data_path = locals()['var_function-call-12660024993988869347']

with open(clinical_data_path, 'r') as f:
    clinical_records = json.load(f)

with open(molecular_data_path, 'r') as f:
    molecular_records = json.load(f)

# Process clinical data
clinical_rows = []
barcode_pattern = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')

for record in clinical_records:
    desc = record.get('Patient_description', '')
    histology = record.get('histological_type', '')
    
    # Extract barcode
    match = barcode_pattern.search(desc)
    if match:
        barcode = match.group(1)
        clinical_rows.append({'ParticipantBarcode': barcode, 'histology': histology})

df_clinical = pd.DataFrame(clinical_rows)

# Process molecular data
df_molecular = pd.DataFrame(molecular_records)

# Ensure numeric
df_molecular['normalized_count'] = pd.to_numeric(df_molecular['normalized_count'], errors='coerce')

# Merge
# Note: molecular data ParticipantBarcode might be just the patient ID, matching the extracted barcode.
merged_df = pd.merge(df_clinical, df_molecular, on='ParticipantBarcode', how='inner')

# Filter valid expression
merged_df = merged_df.dropna(subset=['normalized_count'])

# Calculate log10(expression + 1)
merged_df['log_expression'] = np.log10(merged_df['normalized_count'] + 1)

# Group by histology and calculate mean
result_df = merged_df.groupby('histology')['log_expression'].mean().reset_index()

# Format results
results = {}
for _, row in result_df.iterrows():
    results[row['histology']] = round(row['log_expression'], 4)

print("__RESULT__:")
print(json.dumps(results))"""

